        uint8 accountId;
        bool cross;
        uint64 expiry;
        address agent;
        bytes signature;
    }

    struct ExecuteOTCTradeReq {
        OTCTradeReq trade;
        //
        AcceptOTCPartialData makerData;
        AcceptOTCPartialData takerData;
        //
        uint64 execMsgExpiry;
        bytes execSig;
    }

    // ---- internal ----

    struct MarketCache {
        address market;
        TokenId tokenId;
        uint32 maturity;
        uint8 tickStep;
    }
}

